 * @param {string | null} cpuInfoContent - The content of the cpuinfo file.
 * @returns {object | null} - Parsed CPU information or null if input is invalid.
 */
function parseProcCPUInfo(cpuInfoContent) {
  if (!cpuInfoContent) {
    console.warn('CPU info content is null or undefined. Skipping parsing.');
    return null;
  }
  // Existing parsing logic for cpuinfo content...
  const cpuInfo = {};
  // Example: cpuInfoContent.split('\n').forEach(line => {
  //   const match = line.match(/^(model name)\s*:\s*(.*)$/);
  //   if (match) {
  //     cpuInfo[match[1]] = match[2];
  //   }
  // });
  return cpuInfo;
}

/**
 * Safely parses the content of /proc/meminfo.
 * @param {string | null} memInfoContent - The content of the meminfo file.
 * @returns {object | null} - Parsed memory information or null if input is invalid.
 */
function parseProcMeminfo(memInfoContent) {
  if (!memInfoContent) {
    console.warn('Memory info content is null or undefined. Skipping parsing.');
    return null;
  }
  // Existing parsing logic for meminfo content...
  const memInfo = {};
  // Example: memInfoContent.split('\n').forEach(line => {
  //   const match = line.match(/^(\w+):\s*(\d+)\s*kB$/);
  //   if (match) {
  //     memInfo[match[1]] = parseInt(match[2], 10);
  //   }
  // });
  return memInfo;
}
```

